window.docContents[175].resolve({"/Class-Field-Theory-and-Galois-Theory/Local-fields-and-complete-discrete-valuation-rings/#AINTLIB-___-An-Atlas-of-Number-Theory-in-Lean--Class-Field-Theory-and-Galois-Theory--Local-fields-and-complete-discrete-valuation-rings--Local-Fields-and-Complete-Discrete-Valuation-Rings":{"contents":"A (nonarchimedean) local field is a field  that is complete with respect to a discrete\nvaluation  and has finite residue field. A mixed characteristic local field is a finite\nextension of the field  of -adic numbers; an equal characteristic local field\nis a finite extension of the field  of formal Laurent series over\n.\nFormalised in LocalClassFieldTheory: LocalField, MixedCharLocalField, EqCharLocalField — sorry-free.\n\n","context":"AINTLIB — An Atlas of Number Theory in Lean\u0009Class Field Theory and Galois Theory\u0009Local fields and complete discrete valuation rings","header":"4.5.1. Local Fields and Complete Discrete Valuation Rings","id":"/Class-Field-Theory-and-Galois-Theory/Local-fields-and-complete-discrete-valuation-rings/#AINTLIB-___-An-Atlas-of-Number-Theory-in-Lean--Class-Field-Theory-and-Galois-Theory--Local-fields-and-complete-discrete-valuation-rings--Local-Fields-and-Complete-Discrete-Valuation-Rings"}});